import type { MockOrderbookSnapshot } from "../mockOrderbookEngine";
import { getJellyRowAtFrame } from "./jellyData";
import { getJellyReplayFrameIndex } from "./jellyReplayState";
import { jellyOrderbookByFrame } from "./jellyOrderbookLevels";

function mockTradePriceStep(price: number): number {
  if (price < 1) return 0.0001;
  if (price < 100) return 0.05;
  if (price < 1000) return 1;
  return 20;
}

function roundToTick(price: number, tick: number): number {
  const decimals = tick < 0.0001 ? 8 : tick < 0.01 ? 6 : tick < 1 ? 4 : 2;
  return Number((Math.round(price / tick) * tick).toFixed(decimals));
}

function roundSize(size: number): number {
  return Number(Math.max(0.0001, size).toFixed(4));
}

function buildJellyLevels(
  mid: number,
  depthHL: number,
  slippageHL: number,
  depth = 20,
): MockOrderbookSnapshot {
  const tick = mockTradePriceStep(mid);
  const spreadFactor = 1 + Math.min(slippageHL, 2) * 0.002;
  const halfSpread = tick * spreadFactor;

  const bids: Array<[number, number]> = [];
  const asks: Array<[number, number]> = [];
  const perSideNotional = depthHL / 2;
  const decaySum = (depth * (depth + 1)) / 2;

  for (let i = 0; i < depth; i += 1) {
    const weight = (depth - i) / decaySum;
    const bidPrice = roundToTick(
      Math.max(tick, mid - halfSpread - tick * i),
      tick,
    );
    const askPrice = roundToTick(
      Math.max(tick, mid + halfSpread + tick * i),
      tick,
    );
    const bidSize = roundSize((perSideNotional * weight) / Math.max(bidPrice, tick));
    const askSize = roundSize((perSideNotional * weight) / Math.max(askPrice, tick));
    bids.push([bidPrice, bidSize]);
    asks.push([askPrice, askSize]);
  }

  bids.sort((a, b) => b[0] - a[0]);
  asks.sort((a, b) => b[0] - a[0]);

  return { bids, asks };
}

const snapshotCache = new Map<string, MockOrderbookSnapshot>();

export function clearJellyOrderbookCache(): void {
  snapshotCache.clear();
}

function sliceSnapshot(
  snapshot: MockOrderbookSnapshot,
  depth: number,
): MockOrderbookSnapshot {
  return {
    bids: snapshot.bids.slice(0, depth),
    asks: snapshot.asks.slice(0, depth),
  };
}

function resolveFrameIndex(frameIndex?: number): number {
  return frameIndex ?? getJellyReplayFrameIndex();
}

function sanitizeSnapshot(snapshot: MockOrderbookSnapshot): MockOrderbookSnapshot {
  return {
    asks: snapshot.asks.filter(([price, size]) => price > 0 && size >= 0),
    bids: snapshot.bids.filter(([price, size]) => price > 0 && size >= 0),
  };
}

export function getJellyOrderbookSnapshot(
  frameIndex?: number,
  depth = 20,
): MockOrderbookSnapshot {
  const idx = resolveFrameIndex(frameIndex);
  const cacheKey = `${idx}:${depth}`;
  const cached = snapshotCache.get(cacheKey);
  if (cached) {
    return cached;
  }

  const historic = jellyOrderbookByFrame[idx];
  if (historic && historic.bids.length > 0 && historic.asks.length > 0) {
    const snapshot = sanitizeSnapshot(
      sliceSnapshot({ bids: historic.bids, asks: historic.asks }, depth),
    );
    snapshotCache.set(cacheKey, snapshot);
    return snapshot;
  }

  const row = getJellyRowAtFrame(idx);
  const fallback = sanitizeSnapshot(
    buildJellyLevels(row.priceHL, row.depthHL, row.slippageHL, depth),
  );
  snapshotCache.set(cacheKey, fallback);
  return fallback;
}
