import {
  JELLY_BUCKET_OP_HEDGE,
  JELLY_BUCKET_OP_INSURANCE,
  JELLY_BUCKET_OP_MEME,
  JELLY_BUCKET_OP_SAFE,
} from "./jellyBuckets";
import {
  DEFAULT_JELLY_DEMO_CONFIG,
  REFERENCE_DEPOSIT,
  scaleTimelineAmount,
  type JellyDemoConfig,
} from "./jellyDemoConfig";
