const SATOSHI = 100_000_000;
const MOCK_WALLET_ADDRESS = mockWalletState.address;
const JELLY_ENTRY = getJellyAnchorRow().priceHL;
const OPENAI_MARK = 152.4;
const OPENAI_ENTRY = 148;
const HYPE_MARK = 24.8;
const HYPE_ENTRY = 23.5;

const REFERENCE_SIZES = {
  jellySize: 50_000,
  openaiSize: 80,
  hypeSize: 200,
};

export type JellyReplayPhase = "intro" | "replaying" | "finished";

export type JellyBucketSnapshot = {
  bucketId: string;
  totalEquity: string;
  usedMargin: string;
  unrealizedProfit: string;
  unrealizedLoss: string;
  marginType: "cross" | "isolated";
  collateralAssetIndex: string;
  status: string;
  label: string;
  realizedLoss?: number;
};

export type JellyPortfolioState = {
  positions: JellyPosition[];
  buckets: JellyBucketSnapshot[];
  orders: MockOrder[];
  isJellyLiquidated: boolean;
  liquidationRow: JellyRow | null;
};

function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

function fromSatoshiNum(value: string): number {
  return Number(value) / SATOSHI;
}

function getScaledSizes(config: JellyDemoConfig) {
  const scale = config.depositUsd / REFERENCE_DEPOSIT;
  return {
    scale,
    jellySize: Math.round(REFERENCE_SIZES.jellySize * scale),
    openaiSize: Math.round(REFERENCE_SIZES.openaiSize * scale),
    hypeSize: Math.round(REFERENCE_SIZES.hypeSize * scale),
  };
}

function resolveTimelineLiquidation(
  frameIndex: number,
  anchorIndex: number,
  replayPhase: JellyReplayPhase,
): { liquidated: boolean; liquidationRow: JellyRow | null } {
  const offset = getTimelineFrameOffset(frameIndex, anchorIndex);
  const row = getJellyRow(frameIndex) ?? getJellyAnchorRow();

  if (offset >= TIMELINE_OFFSETS.LIQUIDATION) {
    const liqRow =
      getJellyRow(anchorIndex + TIMELINE_OFFSETS.LIQUIDATION) ?? row;
    return { liquidated: true, liquidationRow: liqRow };
  }

  if (replayPhase === "finished" && offset >= TIMELINE_OFFSETS.LIQUIDATION - 1) {
    return { liquidated: true, liquidationRow: row };
  }

  return { liquidated: false, liquidationRow: null };
}

function buildOpenAiPosition(
  config: JellyDemoConfig,
  timestamp: string,
): JellyPosition {
  const { scale, openaiSize } = getScaledSizes(config);
  const unrealizedProfit = (OPENAI_MARK - OPENAI_ENTRY) * openaiSize;
  const marginBalance = (OPENAI_ENTRY * openaiSize) / 20;

  return {
    positionId: "jelly-pos-openai-long-001",
    bucketId: JELLY_BUCKET_OP_SAFE,
    marketIndex: "1",
    address: MOCK_WALLET_ADDRESS,
    symbol: "OPENAI-USDT",
    size: toSatoshiStr(openaiSize),
    side: "SIDE_BUY",
    averageEntryPrice: toSatoshiStr(OPENAI_ENTRY),
    markPrice: toSatoshiStr(OPENAI_MARK),
    leverage: toSatoshiStr(20),
    unrealizedProfit: toSatoshiStr(unrealizedProfit),
    unrealizedLoss: "0",
    liquidationPrice: toSatoshiStr(140.4),
    marginBalance: toSatoshiStr(marginBalance),
    mmr: toSatoshiStr(59.2 * scale),
    status: "active",
    marginMode: "CROSS",
    createdAt: timestamp,
    updatedAt: timestamp,
  };
}

function buildHypePosition(
  config: JellyDemoConfig,
  timestamp: string,
): JellyPosition {
  const { scale, hypeSize } = getScaledSizes(config);
  const unrealizedLoss = (HYPE_MARK - HYPE_ENTRY) * hypeSize;
  const marginBalance = (HYPE_ENTRY * hypeSize) / 15;

  return {
    positionId: "jelly-pos-hype-short-002",
    bucketId: JELLY_BUCKET_OP_HEDGE,
    marketIndex: "13",
    address: MOCK_WALLET_ADDRESS,
    symbol: "HYPE-USDT",
    size: toSatoshiStr(hypeSize),
    side: "SIDE_SELL",
    averageEntryPrice: toSatoshiStr(HYPE_ENTRY),
    markPrice: toSatoshiStr(HYPE_MARK),
    leverage: toSatoshiStr(15),
    unrealizedProfit: "0",
    unrealizedLoss: toSatoshiStr(unrealizedLoss),
    liquidationPrice: toSatoshiStr(28.1),
    marginBalance: toSatoshiStr(marginBalance),
    mmr: toSatoshiStr(31.33 * scale),
    status: "active",
    marginMode: "CROSS",
    createdAt: timestamp,
    updatedAt: timestamp,
  };
}

function buildJellyPosition(
  config: JellyDemoConfig,
  row: JellyRow,
): JellyPosition {
  const { scale, jellySize } = getScaledSizes(config);
  const markPrice = row.priceHL;
  const unrealizedLoss = Math.max(0, (markPrice - JELLY_ENTRY) * jellySize);
  const initialMargin = (JELLY_ENTRY * jellySize) / 3;
  const marginBalance = Math.max(0, initialMargin - unrealizedLoss);

  return {
    positionId: "jelly-pos-jelly-toxic-003",
    bucketId: JELLY_BUCKET_OP_MEME,
    marketIndex: JELLY_MARKET_INDEX,
    address: MOCK_WALLET_ADDRESS,
    symbol: "JELLY-USDT",
    size: toSatoshiStr(jellySize),
    side: "SIDE_BUY",
    averageEntryPrice: toSatoshiStr(JELLY_ENTRY),
    markPrice: toSatoshiStr(markPrice),
    leverage: toSatoshiStr(3),
    unrealizedProfit: "0",
    unrealizedLoss: toSatoshiStr(unrealizedLoss),
    liquidationPrice: toSatoshiStr(JELLY_ENTRY * 0.5),
    marginBalance: toSatoshiStr(marginBalance),
    mmr: toSatoshiStr(96 * scale),
    status: marginBalance <= initialMargin * 0.15 ? "at_risk" : "active",
    marginMode: "ISOLATED",
    createdAt: row.snapshotTime,
    updatedAt: row.snapshotTime,
  };
}

function buildCorrelatedHedgePosition(
  config: JellyDemoConfig,
  row: JellyRow,
): JellyPosition {
  const { scale } = getScaledSizes(config);
  const markPrice = row.priceHL;
  const notional = scaleTimelineAmount(config, 180_000);
  const hedgeSize = Math.max(1, Math.round(notional / markPrice));
  const marginBalance = notional / 10;

  return {
    positionId: "jelly-pos-jelly-hedge-004",
    bucketId: JELLY_BUCKET_OP_HEDGE,
    marketIndex: JELLY_MARKET_INDEX,
    address: MOCK_WALLET_ADDRESS,
    symbol: "JELLY-USDT",
    size: toSatoshiStr(hedgeSize),
    side: "SIDE_SELL",
    averageEntryPrice: toSatoshiStr(markPrice),
    markPrice: toSatoshiStr(markPrice),
    leverage: toSatoshiStr(10),
    unrealizedProfit: "0",
    unrealizedLoss: "0",
    liquidationPrice: toSatoshiStr(markPrice * 1.5),
    marginBalance: toSatoshiStr(marginBalance),
    mmr: toSatoshiStr(48 * scale),
    status: "active",
    marginMode: "CROSS",
    createdAt: row.snapshotTime,
    updatedAt: row.snapshotTime,
  };
}

function aggregateBucket(
  bucketId: string,
  label: string,
  marginType: "cross" | "isolated",
  baseEquity: number,
  positions: JellyPosition[],
  status: string,
  realizedLoss = 0,
): JellyBucketSnapshot {
  const bucketPositions = positions.filter((p) => p.bucketId === bucketId);
  let usedMargin = 0;
  let unrealizedProfit = 0;
  let unrealizedLoss = 0;

  for (const pos of bucketPositions) {
    usedMargin += fromSatoshiNum(pos.marginBalance);
    unrealizedProfit += fromSatoshiNum(pos.unrealizedProfit);
    unrealizedLoss += fromSatoshiNum(pos.unrealizedLoss);
  }

  const netUpnl = unrealizedProfit - unrealizedLoss;
  const totalEquity = baseEquity + netUpnl;

  return {
    bucketId,
    label,
    marginType,
    collateralAssetIndex: "1",
    status,
    usedMargin: toSatoshiStr(usedMargin),
    unrealizedProfit: toSatoshiStr(unrealizedProfit),
    unrealizedLoss: toSatoshiStr(unrealizedLoss),
    totalEquity: toSatoshiStr(Math.max(0, totalEquity)),
    realizedLoss: realizedLoss > 0 ? realizedLoss : undefined,
  };
}

export function getJellyPortfolioState(
  config: JellyDemoConfig = DEFAULT_JELLY_DEMO_CONFIG,
  frameIndex: number = getJellyAnchorIndex(),
  replayPhase: JellyReplayPhase = "intro",
): JellyPortfolioState {
  const anchorIndex = getJellyAnchorIndex();
  const row = getJellyRow(frameIndex) ?? getJellyAnchorRow();
  const anchorRow = getJellyAnchorRow();
  const offset = getTimelineFrameOffset(frameIndex, anchorIndex);
  const timeline = applyBucketTimeline(config, frameIndex, anchorIndex);
  const { liquidated, liquidationRow } = resolveTimelineLiquidation(
    frameIndex,
    anchorIndex,
    replayPhase,
  );

  const openaiPos = buildOpenAiPosition(config, row.snapshotTime);
  const hypePos = buildHypePosition(config, row.snapshotTime);
  const positions: JellyPosition[] = [openaiPos, hypePos];

  if (!liquidated) {
    positions.push(buildJellyPosition(config, row));
  }

  if (offset >= TIMELINE_OFFSETS.HEALTH_CHECK) {
    positions.push(buildCorrelatedHedgePosition(config, row));
  }

  const buckets: JellyBucketSnapshot[] = [
    aggregateBucket(
      JELLY_BUCKET_OP_SAFE,
      "OP-SAFE",
      "cross",
      timeline.OP_SAFE.baseEquity,
      positions,
      timeline.OP_SAFE.status,
    ),
    aggregateBucket(
      JELLY_BUCKET_OP_MEME,
      "OP-MEME",
      "isolated",
      timeline.OP_MEME.baseEquity,
      positions,
      timeline.OP_MEME.status,
      timeline.OP_MEME.realizedLoss,
    ),
    aggregateBucket(
      JELLY_BUCKET_OP_HEDGE,
      "OP-HEDGE",
      "cross",
      timeline.OP_HEDGE.baseEquity,
      positions,
      timeline.OP_HEDGE.status,
    ),
    aggregateBucket(
      JELLY_BUCKET_OP_INSURANCE,
      "OP-INSURANCE",
      "isolated",
      timeline.OP_INSURANCE.baseEquity,
      positions,
      timeline.OP_INSURANCE.status,
    ),
  ];

  const orders: MockOrder[] = [...buildJellyEntryOrders(config, anchorRow)];
  if (offset >= TIMELINE_OFFSETS.HEALTH_CHECK) {
    const hedgeRow = getJellyRow(anchorIndex + TIMELINE_OFFSETS.HEALTH_CHECK) ?? row;
    orders.push(buildJellyHedgeOrder(config, hedgeRow));
  }
  if (liquidated && liquidationRow) {
    orders.push(buildJellyLiquidationOrder(config, liquidationRow));
  }

  return {
    positions,
    buckets,
    orders,
    isJellyLiquidated: liquidated,
    liquidationRow,
  };
}

export function getJellyPositionsFromState(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): JellyPosition[] {
  return getJellyPortfolioState(
    config ?? DEFAULT_JELLY_DEMO_CONFIG,
    frameIndex ?? getJellyAnchorIndex(),
    replayPhase ?? "intro",
  ).positions.map((p) => ({ ...p }));
}

export function getJellyBucketsFromState(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): JellyBucketSnapshot[] {
  return getJellyPortfolioState(
    config ?? DEFAULT_JELLY_DEMO_CONFIG,
    frameIndex ?? getJellyAnchorIndex(),
    replayPhase ?? "intro",
  ).buckets.map((b) => ({ ...b }));
}

export function getJellyOrderHistoryFromState(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): MockOrder[] {
  return getJellyPortfolioState(
    config ?? DEFAULT_JELLY_DEMO_CONFIG,
    frameIndex ?? getJellyAnchorIndex(),
    replayPhase ?? "intro",
  ).orders.map((o) => ({ ...o }));
}

export function cloneJellyPositionsFromState(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): JellyPosition[] {
  return getJellyPositionsFromState(config, frameIndex, replayPhase);
}

export function cloneJellyBucketsFromState(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): JellyBucketSnapshot[] {
  return getJellyBucketsFromState(config, frameIndex, replayPhase);
}

export function jellyBucketSnapshotToRawBucket(snapshot: JellyBucketSnapshot) {
  return {
    bucketId: snapshot.bucketId,
    totalEquity: snapshot.totalEquity,
    bucketType: snapshot.marginType,
    collateralAssetIndex: snapshot.collateralAssetIndex,
    status: snapshot.status,
    usedMargin: snapshot.usedMargin,
    unrealizedProfit: snapshot.unrealizedProfit,
    unrealizedLoss: snapshot.unrealizedLoss,
  };
}

