import { DEFAULT_JELLY_DEMO_CONFIG, type JellyDemoConfig } from "./jellyDemoConfig";
import { getJellyAnchorIndex } from "./jellyData";
import type { JellyBucket } from "./jellyBuckets";
import {
  getJellyBucketsFromState,
  type JellyBucketSnapshot,
} from "./jellyPortfolioState";

function snapshotToBucket(
  snapshot: JellyBucketSnapshot,
): JellyBucket {
  return {
    bucketId: snapshot.bucketId,
    totalEquity: snapshot.totalEquity,
    marginType: snapshot.marginType,
    collateralAssetIndex: snapshot.collateralAssetIndex,
    status: snapshot.status,
    label: snapshot.label,
  };
}

export function buildJellyBucketsFromConfig(
  config: JellyDemoConfig = DEFAULT_JELLY_DEMO_CONFIG,
): JellyBucket[] {
  return getJellyBucketsFromState(config, getJellyAnchorIndex(), "intro").map(snapshotToBucket);
}

export function cloneJellyBucketsFromConfig(
  config: JellyDemoConfig = DEFAULT_JELLY_DEMO_CONFIG,
): JellyBucket[] {
  return buildJellyBucketsFromConfig(config).map((b) => ({ ...b }));
}

export function cloneJellyBuckets(): JellyBucket[] {
  return cloneJellyBucketsFromConfig();
}

export function getJellyBuckets(): JellyBucket[] {
  return buildJellyBucketsFromConfig();
}

export const jellyBuckets: JellyBucket[] = buildJellyBucketsFromConfig();
