import { mockWalletState, JELLY_MARKET_INDEX } from "../demoData";
import { mockHashId } from "../mockHashId";
import type { MockOrder } from "../orders";
import {
  JELLY_BUCKET_OP_HEDGE,
  JELLY_BUCKET_OP_MEME,
  JELLY_BUCKET_OP_SAFE,
} from "./jellyBuckets";
import {
  REFERENCE_DEPOSIT,
  scaleTimelineAmount,
  type JellyDemoConfig,
  DEFAULT_JELLY_DEMO_CONFIG,
} from "./jellyDemoConfig";
import { TIMELINE_AMOUNTS } from "./jellyBucketTimeline";
import { type JellyRow, getJellyAnchorRow } from "./jellyData";

const SATOSHI = 100_000_000;
const MOCK_WALLET_ADDRESS = mockWalletState.address;
const JELLY_ENTRY = getJellyAnchorRow().priceHL;

const REFERENCE_SIZES = {
  jellySize: 50_000,
  openaiSize: 80,
  hypeSize: 200,
};

function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

function scaledSize(config: JellyDemoConfig, base: number): number {
  return Math.round(base * (config.depositUsd / REFERENCE_DEPOSIT));
}

export function buildJellyEntryOrders(
  config: JellyDemoConfig = DEFAULT_JELLY_DEMO_CONFIG,
  anchorRow: JellyRow = getJellyAnchorRow(),
): MockOrder[] {
  const ts = anchorRow.snapshotTime;
  const openaiSize = scaledSize(config, REFERENCE_SIZES.openaiSize);
  const hypeSize = scaledSize(config, REFERENCE_SIZES.hypeSize);
  const jellySize = scaledSize(config, REFERENCE_SIZES.jellySize);

  return [
    {
      orderId: mockHashId("mock:jelly:openai-entry"),
      marketIndex: "1",
      bucketId: JELLY_BUCKET_OP_SAFE,
      address: MOCK_WALLET_ADDRESS,
      side: "SIDE_BUY",
      type: "ORDER_TYPE_MARKET",
      orderType: "ORDER_TYPE_MARKET",
      price: toSatoshiStr(148),
      quantity: toSatoshiStr(openaiSize),
      filledQuantity: toSatoshiStr(openaiSize),
      averagePrice: toSatoshiStr(148),
      avgPrice: 148,
      status: "ORDER_STATUS_FILLED",
      timestamp: ts,
      timeInForce: "TIME_IN_FORCE_IOC",
      leverage: toSatoshiStr(20),
    },
    {
      orderId: mockHashId("mock:jelly:hype-entry"),
      marketIndex: "13",
      bucketId: JELLY_BUCKET_OP_HEDGE,
      address: MOCK_WALLET_ADDRESS,
      side: "SIDE_SELL",
      type: "ORDER_TYPE_MARKET",
      orderType: "ORDER_TYPE_MARKET",
      price: toSatoshiStr(23.5),
      quantity: toSatoshiStr(hypeSize),
      filledQuantity: toSatoshiStr(hypeSize),
      averagePrice: toSatoshiStr(23.5),
      avgPrice: 23.5,
      status: "ORDER_STATUS_FILLED",
      timestamp: ts,
      timeInForce: "TIME_IN_FORCE_IOC",
      leverage: toSatoshiStr(15),
    },
    {
      orderId: mockHashId("mock:jelly:jelly-entry"),
      marketIndex: JELLY_MARKET_INDEX,
      bucketId: JELLY_BUCKET_OP_MEME,
      address: MOCK_WALLET_ADDRESS,
      side: "SIDE_BUY",
      type: "ORDER_TYPE_MARKET",
      orderType: "ORDER_TYPE_MARKET",
      price: toSatoshiStr(JELLY_ENTRY),
      quantity: toSatoshiStr(jellySize),
      filledQuantity: toSatoshiStr(jellySize),
      averagePrice: toSatoshiStr(JELLY_ENTRY),
      avgPrice: JELLY_ENTRY,
      status: "ORDER_STATUS_FILLED",
      timestamp: ts,
      timeInForce: "TIME_IN_FORCE_IOC",
      leverage: toSatoshiStr(3),
    },
  ];
}

export function buildJellyHedgeOrder(
  config: JellyDemoConfig,
  hedgeRow: JellyRow,
): MockOrder {
  const markPrice = hedgeRow.priceHL;
  const notional = scaleTimelineAmount(config, 180_000);
  const hedgeSize = Math.max(1, Math.round(notional / markPrice));

  return {
    orderId: mockHashId("mock:jelly:jelly-hedge"),
    marketIndex: JELLY_MARKET_INDEX,
    bucketId: JELLY_BUCKET_OP_HEDGE,
    address: MOCK_WALLET_ADDRESS,
    side: "SIDE_SELL",
    type: "ORDER_TYPE_MARKET",
    orderType: "ORDER_TYPE_MARKET",
    price: toSatoshiStr(markPrice),
    quantity: toSatoshiStr(hedgeSize),
    filledQuantity: toSatoshiStr(hedgeSize),
    averagePrice: toSatoshiStr(markPrice),
    avgPrice: markPrice,
    status: "ORDER_STATUS_FILLED",
    timestamp: hedgeRow.snapshotTime,
    timeInForce: "TIME_IN_FORCE_IOC",
    leverage: toSatoshiStr(10),
  };
}

export function buildJellyLiquidationOrder(
  config: JellyDemoConfig,
  liquidationRow: JellyRow,
): MockOrder {
  const jellySize = scaledSize(config, REFERENCE_SIZES.jellySize);
  const fillPrice = liquidationRow.priceHL;
  const loss = scaleTimelineAmount(config, TIMELINE_AMOUNTS.MEME_LIQUIDATION_LOSS);

  return {
    orderId: mockHashId("mock:jelly:jelly-liquidation"),
    marketIndex: JELLY_MARKET_INDEX,
    bucketId: JELLY_BUCKET_OP_MEME,
    address: MOCK_WALLET_ADDRESS,
    side: "SIDE_SELL",
    type: "ORDER_TYPE_LIQUIDATION",
    orderType: "ORDER_TYPE_LIQUIDATION",
    price: toSatoshiStr(fillPrice),
    quantity: toSatoshiStr(jellySize),
    filledQuantity: toSatoshiStr(jellySize),
    averagePrice: toSatoshiStr(fillPrice),
    avgPrice: fillPrice,
    status: "ORDER_STATUS_FILLED",
    timestamp: liquidationRow.snapshotTime,
    timeInForce: "TIME_IN_FORCE_IOC",
    leverage: toSatoshiStr(3),
    reduceOnly: true,
    estimatePnl: -loss,
    triggerCondition: "LIQUIDATION",
  };
}
