export function getJellyAnchorIndex(): number {
  const idx = jellyData.findIndex(
    (row) => row.date === '2025-03-26' && row.time === '21:00',
  );
  return idx >= 0 ? idx : jellyData.length - 1;
}

export function getJellyAnchorRow(): JellyRow {
  return jellyData[getJellyAnchorIndex()] ?? jellyData[jellyData.length - 1]!;
}

export function getJellyHlDelistIndex(): number {
  const idx = jellyData.findIndex((row) => row.snapshotTime === JELLY_HL_DELIST_SNAPSHOT);
  return idx >= 0 ? idx : jellyData.findIndex((row) => row.priceSource === 'binance');
}

export function isJellyHlDelistFrame(index: number): boolean {
  return index === getJellyHlDelistIndex();
}

export function getJellyPriceSourceLabel(row: JellyRow): string {
  return row.priceSource === 'binance' ? 'Binance futures' : 'Hyperliquid';
}

export function getJellyRow(index: number): JellyRow | undefined {
  return jellyData[index];
}

export function getJellyReplayRange(): [number, number] {
  const anchor = getJellyAnchorIndex();
  return [anchor, jellyData.length - 1];
}

export function getJellyRowAtFrame(frameIndex?: number): JellyRow {
  const idx = frameIndex ?? getJellyAnchorIndex();
  return getJellyRow(idx) ?? getJellyAnchorRow();
}

export function getJellyChartWindow(endIndex: number = getJellyAnchorIndex()): JellyRow[] {
  const anchor = getJellyAnchorIndex();
  const cappedEnd = Math.min(Math.max(endIndex, anchor), jellyData.length - 1);
  return jellyData.slice(anchor, cappedEnd + 1);
}

export type JellyCandle = {
  time: number;
  open: number;
  high: number;
  low: number;
  close: number;
};

export function jellyRowsToCandles(rows: JellyRow[]): JellyCandle[] {
  return rows.map((row, i) => {
    const prev = i > 0 ? rows[i - 1]!.priceHL : row.priceHL;
    const next = i < rows.length - 1 ? rows[i + 1]!.priceHL : row.priceHL;
    const open = prev;
    const close = row.priceHL;
    const high = Math.max(open, close, next);
    const low = Math.min(open, close, next);
    const time = Math.floor(new Date(row.snapshotTime).getTime() / 1000);
    return { time, open, high, low, close };
  });
}
