import type { MockOrder } from "../orders";
import {
  DEFAULT_JELLY_DEMO_CONFIG,
  type JellyDemoConfig,
} from "./jellyDemoConfig";
import { getJellyAnchorIndex } from "./jellyData";
import {
  getJellyOrderHistoryFromState,
  type JellyReplayPhase,
} from "./jellyPortfolioState";

export function getJellyOrderHistory(
  config?: JellyDemoConfig,
  frameIndex?: number,
  replayPhase?: JellyReplayPhase,
): MockOrder[] {
  return getJellyOrderHistoryFromState(
    config ?? DEFAULT_JELLY_DEMO_CONFIG,
    frameIndex ?? getJellyAnchorIndex(),
    replayPhase ?? "intro",
  );
}
