import type { MockRawTrade } from "../demoData";
import { mockWalletState, JELLY_MARKET_INDEX } from "../demoData";
import {
  getJellyAnchorIndex,
  getJellyRow,
  jellyData,
  type JellyRow,
} from "./jellyData";
import { getJellyReplayFrameIndex } from "./jellyReplayState";

const SATOSHI = 100_000_000;
const MOCK_WALLET = mockWalletState.address;
const MAX_JELLY_TRADE_HISTORY = 100;
const MINUTES_PER_DAY = 24 * 60;

const tradeMetaById = new Map<string, boolean>();
let tradeHistory: MockRawTrade[] = [];
let cumulativeVolumeUsd = 0;
let lastProcessedFrame = -1;
let tradeSequence = 0;

function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

function priceTick(price: number): number {
  if (price < 0.01) return 0.0001;
  if (price < 1) return 0.0001;
  if (price < 100) return 0.05;
  return 1;
}

function roundToTick(price: number, tick: number): number {
  const decimals = tick < 0.0001 ? 8 : tick < 0.01 ? 6 : 4;
  return Number((Math.round(price / tick) * tick).toFixed(decimals));
}

function baseTradeSize(row: JellyRow, prevRow: JellyRow | undefined): number {
  const price = Math.max(row.priceHL, 0.0001);
  const slippageBoost = 1 + Math.min(row.slippageHL ?? 0, 10) * 0.25;
  const moveBoost =
    prevRow && prevRow.priceHL > 0
      ? 1 + Math.min(5, Math.abs(row.priceHL - prevRow.priceHL) / prevRow.priceHL * 8)
      : 1;
  const depthBoost =
    row.depthHL > 0 ? Math.min(4, 800_000 / row.depthHL + 0.5) : 1.5;
  const notionalTarget = 2500 * slippageBoost * moveBoost * depthBoost;
  return Math.max(100, notionalTarget / price);
}

function tradesPerFrame(row: JellyRow, prevRow: JellyRow | undefined): number {
  const slippageBoost = Math.min(row.slippageHL ?? 0, 8);
  const moveBoost =
    prevRow && prevRow.priceHL > 0
      ? Math.abs(row.priceHL - prevRow.priceHL) / prevRow.priceHL * 20
      : 0;
  return Math.min(16, Math.max(4, Math.round(4 + slippageBoost + moveBoost)));
}

function appendTrade(
  price: number,
  size: number,
  timestamp: number,
  frameIndex: number,
  isBuyerMaker: boolean,
): void {
  tradeSequence += 1;
  const tradeId = `jelly-trade-${frameIndex}-${tradeSequence}`;
  const trade: MockRawTrade = {
    tradeId,
    buyOrderId: `jelly-buy-${tradeSequence}`,
    sellOrderId: `jelly-sell-${tradeSequence}`,
    price: toSatoshiStr(price),
    quantity: toSatoshiStr(size),
    timestamp: String(timestamp),
    marketIndex: JELLY_MARKET_INDEX,
    makerFee: "0",
    takerFee: "0",
    dualWriteId: "",
    sequenceId: `jelly-seq-${frameIndex}-${tradeSequence}`,
    tradeType: tradeSequence % 2 === 0 ? "TRADE_TYPE_BUY" : "TRADE_TYPE_SELL",
    buyAddress: isBuyerMaker
      ? "0xdeadbeef000000000000000000000000000001"
      : MOCK_WALLET,
    sellAddress: isBuyerMaker
      ? MOCK_WALLET
      : "0xdeadbeef000000000000000000000000000001",
  };
  tradeHistory.unshift(trade);
  tradeMetaById.set(tradeId, isBuyerMaker);
  cumulativeVolumeUsd += price * size;
  if (tradeHistory.length > MAX_JELLY_TRADE_HISTORY) {
    const removed = tradeHistory.pop();
    if (removed) tradeMetaById.delete(removed.tradeId);
  }
}

function appendTradesForFrame(frameIndex: number): void {
  const row = getJellyRow(frameIndex);
  if (!row) return;

  const prevRow = frameIndex > 0 ? getJellyRow(frameIndex - 1) : undefined;
  const anchorTs = new Date(row.snapshotTime).getTime();
  const tick = priceTick(row.priceHL);
  const count = tradesPerFrame(row, prevRow);
  const baseSize = baseTradeSize(row, prevRow);
  const rising = prevRow ? row.priceHL >= prevRow.priceHL : true;

  for (let i = 0; i < count; i += 1) {
    const offsetSteps = Math.round((i - count / 2) * (0.5 + (i % 3) * 0.25));
    const price = roundToTick(
      Math.max(tick, row.priceHL + offsetSteps * tick),
      tick,
    );
    const size = baseSize * (0.55 + (i % 5) * 0.18);
    const isBuyerMaker = rising ? i % 3 !== 0 : i % 3 === 0;
    const timestamp = anchorTs - (count - i) * 3500;
    appendTrade(price, size, timestamp, frameIndex, isBuyerMaker);
  }
}

/** Reset accumulated tape when replay restarts. */
export function resetJellyTradeHistory(): void {
  tradeHistory = [];
  tradeMetaById.clear();
  cumulativeVolumeUsd = 0;
  lastProcessedFrame = -1;
  tradeSequence = 0;
}

function ensureTradesThroughFrame(frameIndex: number): void {
  const anchor = getJellyAnchorIndex();
  const target = Math.max(anchor, frameIndex);

  if (lastProcessedFrame < anchor - 1) {
    resetJellyTradeHistory();
  }

  const start =
    lastProcessedFrame < anchor ? anchor : lastProcessedFrame + 1;
  for (let i = start; i <= target; i += 1) {
    appendTradesForFrame(i);
    lastProcessedFrame = i;
  }
}

export function getJellyTradeIsBuyerMaker(tradeId: string): boolean | undefined {
  return tradeMetaById.get(tradeId);
}

export function getJellyCumulativeVolumeUsd(frameIndex?: number): number {
  const idx = frameIndex ?? getJellyReplayFrameIndex();
  ensureTradesThroughFrame(idx);
  return cumulativeVolumeUsd;
}

function volumeUsdForFrameRange(start: number, end: number): number {
  let total = 0;
  for (let i = start; i <= end; i += 1) {
    const row = getJellyRow(i);
    const prev = i > 0 ? getJellyRow(i - 1) : undefined;
    if (!row) continue;
    const count = tradesPerFrame(row, prev);
    const size = baseTradeSize(row, prev);
    for (let t = 0; t < count; t += 1) {
      total += row.priceHL * size * (0.55 + (t % 5) * 0.18);
    }
  }
  return total;
}

export function getJellyTrades(frameIndex?: number): MockRawTrade[] {
  const idx = frameIndex ?? getJellyReplayFrameIndex();
  ensureTradesThroughFrame(idx);
  return tradeHistory.map((trade) => ({ ...trade }));
}

/** @deprecated use getJellyTrades() — kept for static import compatibility */
export const jellyTrades: MockRawTrade[] = getJellyTrades();

export function getJellyTickerMeta(frameIndex?: number): {
  change24h: number;
  volume24h: number;
  openInterest: number;
  price: number;
} {
  const idx = frameIndex ?? getJellyReplayFrameIndex();
  ensureTradesThroughFrame(idx);
  const row = jellyData[idx] ?? jellyData[getJellyAnchorIndex()]!;
  const window24hStart = Math.max(getJellyAnchorIndex(), idx - MINUTES_PER_DAY);
  const anchorRow = jellyData[getJellyAnchorIndex()]!;
  const refRow = jellyData[window24hStart] ?? anchorRow;
  const change24h =
    refRow.priceHL > 0
      ? ((row.priceHL - refRow.priceHL) / refRow.priceHL) * 100
      : 0;

  const volume24h = volumeUsdForFrameRange(window24hStart, idx);

  return {
    price: row.priceHL,
    change24h,
    volume24h,
    openInterest: row.depthHL * 2.5,
  };
}
