import { DEFAULT_JELLY_DEMO_CONFIG } from "./jellyDemoConfig";
import { getJellyAnchorIndex, getJellyAnchorRow } from "./jellyData";
import { getJellyPositionsFromState } from "./jellyPortfolioState";

export type JellyPosition = ReturnType<typeof getJellyPositionsFromState>[number];

export const jellyPositions: JellyPosition[] = getJellyPositionsFromState(
  DEFAULT_JELLY_DEMO_CONFIG,
  getJellyAnchorIndex(),
  "intro",
);

export function cloneJellyPositions(): JellyPosition[] {
  return jellyPositions.map((position) => ({ ...position }));
}

export function getJellyPositions(
  config = DEFAULT_JELLY_DEMO_CONFIG,
  frameIndex = getJellyAnchorIndex(),
  replayPhase: "intro" | "replaying" | "finished" = "intro",
): JellyPosition[] {
  return getJellyPositionsFromState(config, frameIndex, replayPhase);
}

export function cloneJellyPositionsFromConfig(
  config = DEFAULT_JELLY_DEMO_CONFIG,
  frameIndex = getJellyAnchorIndex(),
  replayPhase: "intro" | "replaying" | "finished" = "intro",
): JellyPosition[] {
  return getJellyPositionsFromState(config, frameIndex, replayPhase).map((p) => ({ ...p }));
}

export function buildJellyPositionsFromConfig(
  config = DEFAULT_JELLY_DEMO_CONFIG,
  _row = getJellyAnchorRow(),
): JellyPosition[] {
  return getJellyPositionsFromState(config, getJellyAnchorIndex(), "intro");
}
