import type { UTCTimestamp } from "lightweight-charts";
import {
  getJellyAnchorIndex,
  getJellyChartWindow,
  getJellyRow,
  jellyData,
  type JellyRow,
} from "./jellyData";
import type { JellyReplayPhase } from "./jellyPortfolioState";
import {
  jellyLiquidationData,
  type JellyLiquidationFrame,
} from "./jellyLiquidationData";
import {
  jellyMorpLiquidationData,
  type JellyMorpLiquidationFrame,
} from "./jellyMorpLiquidationData";

const MORP_FLOOR_RATIO = 0.75;
const MORP_STABILITY_PEAK = 1.35;

export type JellyLiquidityPoint = {
  time: UTCTimestamp;
  depthHL: number;
  depthMorp: number;
  slippageHL: number;
  slippageMorp: number;
};

export type JellyLiquidationPoint = {
  time: UTCTimestamp;
  liqCountHL: number;
  liqCountMorp: number;
};

function rowToTime(row: JellyRow): UTCTimestamp {
  return Math.floor(new Date(row.snapshotTime).getTime() / 1000) as UTCTimestamp;
}

function synthesizeDepthMorp(
  depthHL: number,
  anchorDepth: number,
  stressRatio: number,
): number {
  const morpStabilityFactor = 1.0 + (MORP_STABILITY_PEAK - 1.0) * stressRatio;
  return Math.max(depthHL * morpStabilityFactor, anchorDepth * MORP_FLOOR_RATIO);
}

function synthesizeSlippageMorp(
  slippageHL: number,
  depthMorp: number,
  depthHL: number,
): number {
  const ratio = depthHL > 0 ? depthMorp / depthHL : 1;
  const dampener = Math.min(1.0, 0.55 + 0.45 * ratio);
  return slippageHL * dampener;
}

export function getJellyLiquidityComparisonWindow(
  endIndex: number,
): JellyLiquidityPoint[] {
  const rows = getJellyChartWindow(endIndex);
  const anchorDepth = jellyData[getJellyAnchorIndex()]?.depthHL ?? 0;

  return rows.map((row) => {
    const stressRatio =
      anchorDepth > 0 ? Math.min(1, row.depthHL / anchorDepth) : 1;
    const depthMorp = synthesizeDepthMorp(row.depthHL, anchorDepth, stressRatio);
    const slippageMorp = synthesizeSlippageMorp(
      row.slippageHL,
      depthMorp,
      row.depthHL,
    );
    return {
      time: rowToTime(row),
      depthHL: row.depthHL,
      depthMorp,
      slippageHL: row.slippageHL,
      slippageMorp,
    };
  });
}

function liquidationFrameByIndex(index: number): JellyLiquidationFrame | undefined {
  return jellyLiquidationData[index];
}

function morpLiquidationFrameByIndex(index: number): JellyMorpLiquidationFrame | undefined {
  return jellyMorpLiquidationData[index];
}

function buildLiquidationSeries(
  endIndex: number,
  replayPhase: JellyReplayPhase,
): JellyLiquidationPoint[] {
  const anchorIndex = getJellyAnchorIndex();
  const cappedEnd = Math.min(
    Math.max(endIndex, anchorIndex),
    jellyData.length - 1,
  );

  const points: JellyLiquidationPoint[] = [];

  for (let i = anchorIndex; i <= cappedEnd; i += 1) {
    const row = getJellyRow(i);
    if (!row) continue;

    const liqFrame = liquidationFrameByIndex(i);
    const liqCountHL = liqFrame?.liqCountHL ?? 0;
    const morpFrame = morpLiquidationFrameByIndex(i);
    const liqCountMorp =
      morpFrame !== undefined ? Math.round(morpFrame.liqCountMorp) : 0;

    points.push({
      time: rowToTime(row),
      liqCountHL,
      liqCountMorp,
    });
  }

  if (
    replayPhase === "finished" &&
    points.length > 0 &&
    jellyMorpLiquidationData.length === 0
  ) {
    const last = points[points.length - 1]!;
    if (last.liqCountMorp === 0) {
      last.liqCountMorp = 1;
    }
  }

  return points;
}

export function getJellyLiquidationComparisonWindow(
  endIndex: number,
  replayPhase: JellyReplayPhase = "intro",
): JellyLiquidationPoint[] {
  return buildLiquidationSeries(endIndex, replayPhase);
}
